// src/components/FormAluno.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [confirmSenha, setConfirmSenha] = useState('');
  const [role, setRole] = useState('aluno'); // padrão: 'aluno'
  const [periodos, setPeriodos] = useState([]);
  const [periodoId, setPeriodoId] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Carrega lista de períodos
  useEffect(() => {
    axios.get('/api/periodos')
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, []);

  // Se estivermos editando um aluno, preenche os campos
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setUsuario(alunoEditando.usuario || '');
      // NÃO exibir a senha atual (apenas campo em branco para preencher nova senha, se quiser)
      setSenha('');
      setConfirmSenha('');
      setRole(alunoEditando.role || 'aluno');
      setPeriodoId(alunoEditando.periodo_id || '');
    } else {
      // - Limpa todos os campos
      setNome('');
      setRa('');
      setUsuario('');
      setSenha('');
      setConfirmSenha('');
      setRole('aluno');
      setPeriodoId('');
    }
    setMensagem('');
  }, [alunoEditando]);

  // Valida se duas senhas batem
  function validarSenha() {
    if (alunoEditando) {
      // Se for edição e o usuário **não** preencheu senha (manter em branco), não força validação
      if (!senha && !confirmSenha) {
        return true;
      }
    }
    // Se for novo, ou se for edição e preencheu algo, valide normalmente:
    return senha === confirmSenha;
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMensagem('');

    // 1) Campos obrigatórios:
    if (!nome.trim() || !ra.trim() || !usuario.trim()) {
      setMensagem("Preencha nome, RA e usuário.");
      return;
    }
    // 2) Validar senha/confirm (para cadastro sempre obrigatório, para edição só se preenchido)
    if (!validarSenha()) {
      setMensagem("Senhas não coincidem.");
      return;
    }
    // 3) Se for cadastro novo, senha obrigatória
    if (!alunoEditando && (!senha || !confirmSenha)) {
      setMensagem("A senha é obrigatória para novo aluno.");
      return;
    }

    try {
      if (alunoEditando) {
        // 4.a) Edição: PUT /api/alunos/:id
        await axios.put(`/api/alunos/${alunoEditando.id}`, {
          nome,
          ra,
          periodo_id: periodoId,
          usuario,
          // Se for edição e o campo senha estiver vazio, não incluir senha no payload:
          ...(senha ? { senha } : {}),
          role
        });
        setMensagem("Aluno atualizado com sucesso!");
        onNovoAluno && onNovoAluno();
        onFimEdicao && onFimEdicao();
      } else {
        // 4.b) Cadastro novo: POST /api/alunos
        await axios.post('/api/alunos', {
          nome,
          ra,
          periodo_id: periodoId,
          usuario,
          senha,
          role
        });
        setMensagem("Aluno cadastrado com sucesso!");
        onNovoAluno && onNovoAluno();
        // Limpa campos
        setNome('');
        setRa('');
        setUsuario('');
        setSenha('');
        setConfirmSenha('');
        setRole('aluno');
        setPeriodoId('');
      }
    } catch (err) {
      console.error("Erro ao salvar aluno:", err.response || err);
      // Se o backend devolveu um erro específico:
      if (err.response && err.response.data && err.response.data.error) {
        setMensagem(err.response.data.error);
      } else {
        setMensagem("Erro ao salvar. Tente novamente.");
      }
    }
  };

  return (
    <form onSubmit={handleSubmit} className="max-w-lg mx-auto p-6 bg-white rounded-2xl shadow space-y-4">
      <h2 className="text-2xl font-bold mb-4">
        {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
      </h2>

      <div>
        <label className="block font-medium mb-1">Nome Completo</label>
        <input
          type="text"
          value={nome}
          onChange={e => setNome(e.target.value)}
          className="w-full border rounded px-3 py-2"
          placeholder="Nome completo"
          required
        />
      </div>

      <div>
        <label className="block font-medium mb-1">RA</label>
        <input
          type="text"
          value={ra}
          onChange={e => {
            // só números, até 9 dígitos
            const val = e.target.value.replace(/\D/g, '').slice(0, 9);
            setRa(val);
          }}
          className="w-full border rounded px-3 py-2"
          placeholder="Número de matrícula (RA)"
          required
        />
      </div>

      <div>
        <label className="block font-medium mb-1">Período</label>
        <select
          value={periodoId || ''}
          onChange={e => setPeriodoId(e.target.value)}
          className="w-full border rounded px-3 py-2"
          required
        >
          <option value="">Selecione um período</option>
          {periodos.map(p => (
            <option key={p.id} value={p.id}>
              {p.nome} ({p.turno})
            </option>
          ))}
        </select>
      </div>

      <div>
        <label className="block font-medium mb-1">Usuário</label>
        <input
          type="text"
          value={usuario}
          onChange={e => setUsuario(e.target.value)}
          className="w-full border rounded px-3 py-2"
          placeholder="Nome de usuário (login)"
          required
        />
      </div>

      <div>
        <label className="block font-medium mb-1">
          Senha {alunoEditando ? '(preencha apenas para alterar)' : ''}
        </label>
        <input
          type="password"
          value={senha}
          onChange={e => setSenha(e.target.value)}
          className="w-full border rounded px-3 py-2"
          placeholder={alunoEditando ? 'Nova senha (deixe em branco para manter)' : 'Senha'}
          // required apenas para novo; para edição, não obrigatório
          required={!alunoEditando}
        />
      </div>

      <div>
        <label className="block font-medium mb-1">
          Confirmar Senha {alunoEditando ? '(se alterou)' : ''}
        </label>
        <input
          type="password"
          value={confirmSenha}
          onChange={e => setConfirmSenha(e.target.value)}
          className="w-full border rounded px-3 py-2"
          placeholder={alunoEditando ? 'Confirme a nova senha' : 'Confirme a senha'}
          required={!alunoEditando}
        />
      </div>

      <div>
        <label className="block font-medium mb-1">Perfil / Role</label>
        <select
          value={role}
          onChange={e => setRole(e.target.value)}
          className="w-full border rounded px-3 py-2"
          required
        >
          <option value="aluno">Aluno (padrão)</option>
          <option value="recepcao">Recepção / Admin</option>
        </select>
      </div>

      <div className="mt-6 flex items-center gap-4">
        <button
          type="submit"
          className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
        >
          {alunoEditando ? 'Salvar Alterações' : 'Cadastrar Aluno'}
        </button>
        {alunoEditando && (
          <button
            type="button"
            onClick={onFimEdicao}
            className="ml-2 bg-gray-300 hover:bg-gray-400 text-gray-800 py-2 px-4 rounded-full"
          >
            Cancelar
          </button>
        )}
      </div>

      {mensagem && <p className="mt-4 text-red-600">{mensagem}</p>}
    </form>
  );
}

export default FormAluno;
